// RecurrentTokenNotNil applies the NotNil predicate on the "recurrent_token" field.
func RecurrentTokenNotNil() predicate.PaymentProfile {
	return predicate.PaymentProfile(sql.FieldNotNull(FieldRecurrentToken))
}

// RecurrentTokenEqualFold applies the EqualFold predicate on the "recurrent_token" field.
func RecurrentTokenEqualFold(v string) predicate.PaymentProfile {
	return predicate.PaymentProfile(sql.FieldEqualFold(FieldRecurrentToken, v))
}

// RecurrentTokenContainsFold applies the ContainsFold predicate on the "recurrent_token" field.
func RecurrentTokenContainsFold(v string) predicate.PaymentProfile {
	return predicate.PaymentProfile(sql.FieldContainsFold(FieldRecurrentToken, v))
}

// HasInvoices applies the HasEdge predicate on the "invoices" edge.
func HasInvoices() predicate.PaymentProfile {
	return predicate.PaymentProfile(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, InvoicesTable, InvoicesColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasInvoicesWith applies the HasEdge predicate on the "invoices" edge with a given conditions (other predicates).
func HasInvoicesWith(preds ...predicate.Invoice) predicate.PaymentProfile {
	return predicate.PaymentProfile(func(s *sql.Selector) {
		step := newInvoicesStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PaymentProfile) predicate.PaymentProfile {
	return predicate.PaymentProfile(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PaymentProfile) predicate.PaymentProfile {
	return predicate.PaymentProfile(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PaymentProfile) predicate.PaymentProfile {
	return predicate.PaymentProfile(sql.NotPredicates(p))
}
